  import sailpoint.object.Filter;
  import sailpoint.object.Identity;
  import sailpoint.object.QueryOptions; 
  import sailpoint.tools.Util;
  import sailpoint.object.Custom;
  import java.text.SimpleDateFormat;
  import java.util.Date;
  
  import org.apache.commons.logging.LogFactory;
  import org.apache.commons.logging.Log;
  
  Log logger = LogFactory.getLog("Ascension-Rule-Library-OIM-Data");

  
   /**
   * Method to process the identities and add to custom object when the identity doesnt have email and operid
     * @param outputMap
     * @return
     */
  public Map processIdentities(Map outputMap, String customObjectName){
    logger.debug("Entering processIdentities method");

    List list = new ArrayList();
    Map attributesMap = new HashMap();
    String initialOperId = "initialOperId";
    if(!Util.isEmpty(outputMap) && Util.isNotNullOrEmpty(customObjectName)){
      String personID = outputMap.get("Person ID");
      if(Util.isNotNullOrEmpty(personID)){
       Filter empIDFilter = Filter.eq("employeeId", personID);
       QueryOptions qo = new QueryOptions();
       qo.add(empIDFilter);
        
       Iterator iter = context.search(Identity.class, qo);
        
        if(iter!= null && !iter.hasNext()){
          //Identity is not available
           list.add(personID);
        }
        int count = 0;
        String ministry = "";
        while(iter != null && iter.hasNext()) {
         count++;
          String email = null;
          String operId = null;
          ministry = "";
          Identity identity = iter.next();
          if(identity != null){
             email =  identity.getAttribute("email");
             operId =  identity.getAttribute("operId");
             ministry = identity.getStringAttribute("ministry");
            // for Amita/ascension operId value should be from initialOperId attribute
             if( Util.isNotNullOrEmpty(identity.getStringAttribute(initialOperId)) ){
                 operId =  identity.getStringAttribute(initialOperId);
             }
            outputMap.put("Email Address",email);
            outputMap.put("OprId",operId);
            // Update OU value for listed Ascension ministries
            try{
              Custom generalCustom = context.getObjectByName(Custom.class,"Ascension-custom-generalConfiguration");
              if(generalCustom!=null){
                Object domainworkitemministry = generalCustom.get("domainworkitemministry");
                if(domainworkitemministry instanceof List){
                  if( ((List) domainworkitemministry).contains(ministry) ){
                    String OU = getOUInformation(identity.getName());
                    if(Util.isNotNullOrEmpty(OU)){
                      outputMap.put("OU",OU);
                    }
                  }
                }
                //comment decache //context.decache(generalCustom);
              }
            }catch(Exception ex){
              logger.error("Exception in updateOU "+ex.getMessage());
            }
          } 
        }
        Util.flushIterator(iter);
        attributesMap = outputMap;
      } 
    }

    logger.debug("Exiting processIdentities method");
    return attributesMap;
  }
  
    /**
     * @param updatedDataList
     * @param headerString
     * @return
     */
  public StringBuffer convertData(List updatedDataList,String headerString){
    logger.debug("Entering convertData method");
    StringBuffer data = new StringBuffer();
    int headerLength = 0;
    String[] headerSplit = null;
    if (Util.isNotNullOrEmpty(headerString) && headerString.contains("|")) {
        data.append("#GTC Trusted Source");
        data.append("\n");
        data.append(headerString);
        data.append("\n");
            headerSplit = headerString.split("\\|");
        if (headerSplit != null) {
          headerLength = headerSplit.length;
        }
      }
    if(!Util.isEmpty(updatedDataList)){
        int size = updatedDataList.size();
        int listNum = 0;
        for(int i=0; i<size; i++){
          Map eachMap = updatedDataList.get(i);
          if(!Util.isEmpty(eachMap) && headerSplit != null){
            for(int count=0; count < headerLength; count++){
              String value= eachMap.get(headerSplit[count]);
              data.append(Util.isNotNullOrEmpty(value) ? value : " ");
              if(count != headerLength-1){
                data.append("|");
              }
            }
            if(i<(size-1))
             data.append("\n");
           } 
        }
    }
    logger.debug("Exiting convertData method");
    return data;
  }
  
    /**
     * This method is for creating output file with whole data
     * @param data
     * @param outputFilePath
     */
  public void createOutputFile(StringBuffer data, String outputFilePath){
    logger.debug("Entering createOutputFile method");
     if(data != null && Util.isNotNullOrEmpty(outputFilePath)){
          SimpleDateFormat sf = new SimpleDateFormat("MMddyyyyhhmmss");
          String dateFormat = sf.format(new Date());
          outputFilePath = outputFilePath.replaceAll("MMddyyyyhhmmss", dateFormat);
          BufferedWriter outputFile = null;
        try {
            outputFile =new BufferedWriter(new FileWriter(outputFilePath));
            if(outputFile != null){
              outputFile.append(data.toString());
            }
        } catch (IOException e) {
          logger.error("IOException : "+e.getMessage());
        } finally {
          try {
            outputFile.flush();  
            outputFile.close();
          } catch (IOException e) {
            logger.error("IOException : "+e.getMessage());
          }
        }
    }
     logger.debug("Exiting createOutputFile method");
  }
  
  
  /**
   * Method to full an identity with employeeID as input
     * @param identityName
     * @return
     */
  public Identity findIdentityFromEmployeeID(String identityName){
    Identity id = null;
     if(Util.isNotNullOrEmpty(identityName)){
       Filter empIDFilter = Filter.eq("employeeId", identityName);
       QueryOptions qo = new QueryOptions();
       qo.add(empIDFilter);
        
       Iterator iter = context.search(Identity.class, qo);
       while(iter != null && iter.hasNext()) {
            Identity identity = iter.next();
          if(identity != null){
            return identity;
          }
       }
       Util.flushIterator(iter);
     }
    return id;
  }
   
    /**
   * Method to check eligilibty of identity that is adding if user has both email and operid
     * @param identityName
     * @return
     */
  public String isIdentityEligible(String identityName){
    String message = "";
    if(Util.isNotNullOrEmpty(identityName)){
      Identity idObj = findIdentityFromEmployeeID(identityName);
      if(idObj != null){
        String email = (String) idObj.getAttribute("email");
        String operId = (String) idObj.getAttribute("operId"); 
        String ministry = (String) idObj.getAttribute("ministry"); 
        if(Util.nullSafeCaseInsensitiveEq(ministry,"AMITA Health") && Util.isNotNullOrEmpty(idObj.getStringAttribute("initialOperId")) ){
          operId =  idObj.getStringAttribute("initialOperId");
        }
        if(Util.isNotNullOrEmpty(email) && (!Util.nullSafeCaseInsensitiveEq(ministry,"AMITA Health") || Util.isNotNullOrEmpty(operId)) ){
          message = "true";
        } else if(Util.isEmpty(email)){
          message = "Doesn't have email id in SailPoint";
        } else{
          message = "Belongs to ministry AMITA Health and doesn't have a Network (Logon) ID in SailPoint";
        }
        //comment decache //context.decache(idObj);
      } else {
        message = "Identity doesn't exist in SailPoint";
      }
    }
    return message;
  }
  
   /**
   * Method to remove duplicates from the custom object entry list
     * @param customObjName
     */
    public void removeDuplicatesFromExceptions(String customObjName){
    List removedDuplicates = null;
    if(Util.isNotNullOrEmpty(customObjName)){
      Custom custom = context.getObjectByName(Custom.class, customObjName);
      if(custom != null){
        Object object = custom.get("Exception Identities");
        if(object != null && object instanceof List){
          Set hashSet = new LinkedHashSet(object);
          removedDuplicates = new ArrayList(hashSet);
           custom.put("Exception Identities", removedDuplicates);
           context.saveObject(custom);
           context.commitTransaction();
           //comment decache //context.decache(custom);
        }
      }
    }
  }
